import{_ as t,o as e,c as p,a2 as o}from"./chunks/framework.ZhLefgN8.js";const g=JSON.parse('{"title":"完成首次入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"getting-started/first-deposit.md","filePath":"zh-CN/getting-started/first-deposit.md"}'),r={name:"getting-started/first-deposit.md"};function i(l,a,n,s,d,h){return e(),p("div",null,[...a[0]||(a[0]=[o('<h1 id="完成首次入金" tabindex="-1">完成首次入金 <a class="header-anchor" href="#完成首次入金" aria-label="Permalink to &quot;完成首次入金&quot;">​</a></h1><p>在本教程结束时，你的长桥账户余额将显示港元资金，可以用于购买港股。</p><p>完成这个教程大约需要 <strong>10 分钟操作</strong>，加上等待银行转账处理的时间（港股交易日内约 2 小时）。</p><h2 id="开始前的准备" tabindex="-1">开始前的准备 <a class="header-anchor" href="#开始前的准备" aria-label="Permalink to &quot;开始前的准备&quot;">​</a></h2><p>确认以下三项已就绪：</p><ul><li>长桥账户已开通（可正常登录）</li><li>已在长桥 App 绑定一张香港银行卡</li><li>银行账户中有足够余额</li></ul><p>如果银行卡尚未绑定，请先在 App 中添加：<strong>资产 → 银行卡 → 添加银行卡</strong>。</p><h2 id="第一步-进入存入资金页面" tabindex="-1">第一步：进入存入资金页面 <a class="header-anchor" href="#第一步-进入存入资金页面" aria-label="Permalink to &quot;第一步：进入存入资金页面&quot;">​</a></h2><p>打开长桥 App，点击底部导航栏的**「资产」**。</p><p>你会看到账户总览页面，顶部显示资产总额（目前为 0 或你已有的余额）。</p><p>点击**「存入资金」**按钮。</p><h2 id="第二步-选择入金方式" tabindex="-1">第二步：选择入金方式 <a class="header-anchor" href="#第二步-选择入金方式" aria-label="Permalink to &quot;第二步：选择入金方式&quot;">​</a></h2><p>进入存入资金页面后：</p><ol><li>在币种选择中点击**「港元 HKD」**</li><li>在下方选择你的香港银行卡</li><li>点击**「FPS 转数快」**</li></ol><p>你会看到一个 FPS 识别码（一串数字，如 <code>169152691</code>）。点击旁边的**「复制」**按钮。</p><blockquote><p>这个 FPS ID 就是长桥的收款地址，你接下来要把它转到你的银行 App 里使用。</p></blockquote><h2 id="第三步-在银行-app-发起转账" tabindex="-1">第三步：在银行 App 发起转账 <a class="header-anchor" href="#第三步-在银行-app-发起转账" aria-label="Permalink to &quot;第三步：在银行 App 发起转账&quot;">​</a></h2><p>现在切换到你的银行 App（不要关闭长桥 App，可以返回桌面）。</p><p>在银行 App 中：</p><ol><li>进入<strong>转账</strong>或<strong>FPS 转数快</strong>功能</li><li>选择**「以 FPS 识别码转账」**</li><li>粘贴刚才复制的 FPS ID</li><li>输入转账金额（例如 5,000 港元）</li><li>确认收款人名称显示为 <strong>Long Bridge HK Limited</strong>，然后提交转账</li></ol><p>注意：收款人名称必须是 Long Bridge HK Limited 才代表转账地址正确。</p><p>银行 App 显示「转账成功」后，<strong>立即返回长桥 App</strong>。</p><h2 id="第四步-上传转账凭证" tabindex="-1">第四步：上传转账凭证 <a class="header-anchor" href="#第四步-上传转账凭证" aria-label="Permalink to &quot;第四步：上传转账凭证&quot;">​</a></h2><p>返回长桥 App 的 FPS 转数快入金页面（如果不在该页面，重新进入<strong>资产 → 存入资金 → 港元 → FPS 转数快</strong>）。</p><p>你会看到一个上传凭证的区域：</p><ol><li>点击上传图标</li><li>选择刚才银行 App 的转账成功截图</li><li>确认金额和 FPS ID 可见</li><li>点击**「提交」**</li></ol><blockquote><p>凭证必须在转账后立即上传，拖延会影响入金审核进度。</p></blockquote><p>提交后，你会看到入金申请状态变为**「审核中」**。</p><h2 id="等待资金到账" tabindex="-1">等待资金到账 <a class="header-anchor" href="#等待资金到账" aria-label="Permalink to &quot;等待资金到账&quot;">​</a></h2><p>现在你只需要等待。</p><p><strong>如果是港股交易日（周一至周五 09:00–23:59）</strong>：资金通常在 2 小时内到账。</p><p><strong>如果在其他时段或香港公众假日</strong>：资金会在下一个港股交易日上午 09:40 前到账。</p><p>你可以在<strong>资产 → 存入资金 → 入金记录</strong>里随时查看处理进度，状态会从「审核中」变为「成功」。</p><h2 id="确认完成" tabindex="-1">确认完成 <a class="header-anchor" href="#确认完成" aria-label="Permalink to &quot;确认完成&quot;">​</a></h2><p>当入金记录状态显示「成功」，回到**「资产」**页面。</p><p>你会看到港元余额已更新，显示你刚才存入的金额。</p><p><strong>恭喜！你已完成第一次入金。</strong> 这笔资金现在可以用于购买港股。</p><hr><p>下一步：<a href="./买入第一只港股">买入第一只港股</a></p>',39)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
